var results = $.steps.searchWeb.response.results || [];
var quickSummary = '';
var topUrls = [];
results.forEach(function(r, i) {
  quickSummary += 'RESULT ' + (i + 1) + ': ' + (r.title || '') + '\n';
  quickSummary += 'URL: ' + (r.url || '') + '\n';
  quickSummary += (r.text || '').slice(0, 1500) + '\n\n';
  if (i < 3 && r.url) topUrls.push(r.url);
});
return { quickSummary: quickSummary, topUrls: topUrls, resultCount: results.length };

var quick = $.steps.extractTopResults.output.quickSummary;
var urls = $.steps.extractTopResults.output.topUrls;
var iterations = $.steps.deepScrape.response.iterations || [];
var deepContent = '';
iterations.forEach(function(iter, i) {
  var resp = (iter.scrapePage && iter.scrapePage.response && iter.scrapePage.response.data) ? iter.scrapePage.response.data : null;
  if (resp && resp.markdown) {
    deepContent += '=== DEEP CONTENT ' + (i + 1) + ' ===\n';
    deepContent += 'URL: ' + (urls[i] || '') + '\n';
    deepContent += resp.markdown.slice(0, 3000) + '\n\n';
  }
});
var allContent = quick + '\n--- DEEP SCRAPES ---\n' + deepContent;
return { allContent: allContent.slice(0, 15000) };

var prompt = 'You are an expert assistant. Answer the user's question using the web search results and deep-scraped content provided. Be thorough, accurate, and cite your sources.

';
prompt += 'USER QUESTION: ' + $.input.userMessage + '

';
prompt += 'WEB SOURCES:
' + $.steps.compileAll.output.allContent + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Provide a complete, well-structured answer
';
prompt += '- Use [1], [2], etc. to cite sources
';
prompt += '- Include code examples or step-by-step instructions if relevant
';
prompt += '- Be factual and note any uncertainty

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "answer": "Full detailed answer with citations",
';
prompt += '  "tldr": "1-2 sentence summary",
';
prompt += '  "sources": [{ "num": 1, "title": "...", "url": "..." }],
';
prompt += '  "relatedTopics": ["topic1"]
';
prompt += '}';
return { prompt: prompt };

let raw = $.steps.aiAnswer.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, tldr: '', sources: [], relatedTopics: [] }; }

var ai = $.steps.parseAI.output;
var blocks = [];
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Q:* ' + $.input.userMessage } });
blocks.push({ type: 'divider' });
if (ai.tldr) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*TL;DR:* ' + ai.tldr } });
  blocks.push({ type: 'divider' });
}
var answerChunks = [];
var fullAnswer = ai.answer || '';
for (var idx = 0; idx < fullAnswer.length; idx += 2800) {
  answerChunks.push(fullAnswer.slice(idx, idx + 2800));
}
answerChunks.slice(0, 3).forEach(function(chunk) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: chunk } });
});
if (ai.sources && ai.sources.length > 0) {
  blocks.push({ type: 'divider' });
  var srcText = '*Sources:*\n';
  ai.sources.forEach(function(s) { srcText += '[' + s.num + '] <' + s.url + '|' + s.title + '>\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: srcText.slice(0, 1800) } });
}
if (ai.relatedTopics && ai.relatedTopics.length > 0) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: '*Related:* ' + ai.relatedTopics.join(', ') }] });
}
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa + Firecrawl + Claude AI via One CLI' }] });
var fallback = (ai.tldr || (ai.answer || '').slice(0, 200));
return { blocks: blocks, fallback: fallback };
